INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (1, N'Lima', N'Capital del Perú, centro de conexiones y negocios.', N'Lima es la capital de la República del Perú. Se encuentra situada en la costa central del país, a orillas del océano Pacífico, conformando una extensa y populosa área urbana conocida como Lima Metropolitana.', N'-12.046374', N'-77.042793', 1, 16, N'lima');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (2, N'Trujillo', N'Ciudad de la Eterna Primavera e historia moche.', N'Trujillo es una ciudad peruana, capital del departamento de La Libertad. Es la tercera ciudad más poblada del Perú y destaca por sus monumentos arqueológicos y su clima primaveral constante.', N'-8.11599', N'-79.02998', 1, 22, N'trujillo');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (3, N'Chiclayo', N'Ciudad de la Amistad y rica gastronomía lambayecana.', N'Chiclayo es la capital del departamento de Lambayeque. Conocida por su hospitalidad, mercados esotéricos y los increíbles descubrimientos arqueológicos del Señor de Sipán.', N'-6.77137', N'-79.84088', 1, 28, N'chiclayo');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (4, N'Cajamarca', N'Cuna del encuentro de dos mundos y exquisitos quesos.', N'Cajamarca destaca por su arquitectura colonial en piedra, sus aguas termales de los Baños del Inca y el histórico Cuarto del Rescate donde estuvo prisionero el Inca Atahualpa.', N'-7.16378', N'-78.50027', 1, 24, N'cajamarca');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (5, N'Piura', N'Ciudad del eterno calor, sol y hermosas playas.', N'Piura destaca por su clima cálido, su folclore, sus cerámicas de Chulucanas y las espectaculares playas del norte peruano como Máncora, Colán y Cabo Blanco.', N'-5.19449', N'-80.63282', 1, 9, N'piura');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (6, N'Pacasmayo', N'Puerto histórico y paraíso del windsurf.', N'Pacasmayo es un distrito costero ubicado en La Libertad, famoso por su muelle centenario, sus olas perfectas para deportes acuáticos y su arquitectura republicana.', N'-7.40056', N'-79.57139', 1, 2, N'pacasmayo');
INSERT INTO [destination] ([destinationId], [name], [shortDescription], [longDescription], [lat], [lng], [status], [galeryImageId], [slug]) VALUES (7, N'Chimbote', N'Importante puerto pesquero del norte central.', N'Chimbote destaca por su gran actividad pesquera e industrial. Posee una bahía hermosa y es la puerta de entrada al Callejón de Huaylas desde la costa ancashina.', N'-9.08528', N'-78.57833', 1, 10, N'chimbote');
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (1, N'food', N'Cevichería Mi Barrunto', N'El mejor ceviche tradicional con pescados frescos del día en el distrito de La Victoria.', N'-12.032642312808898', N'-77.02510337706873', 1, 30);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (2, N'location', N'Centro Histórico de Lima', N'Visita guiada por la Plaza Mayor, la Catedral de Lima y las catacumbas de San Francisco.', N'-12.055090347127829', N'-77.05442487340764', 1, 4);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (3, N'activity', N'Parapente en Miraflores', N'Vuela sobre el acantilado de la Costa Verde con instructores calificados.', N'-12.059439517626899', N'-77.03660839270776', 1, 29);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (4, N'location', N'Ciudadela de Chan Chan', N'La ciudad de barro más grande de América Latina precolombina.', N'-8.110003323171826', N'-79.04507311891523', 2, 6);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (5, N'food', N'Shámbar Trujillano', N'Sopa tradicional de los lunes a base de menestras, trigo, piel de cerdo y jamón ahumado.', N'-8.101190513604331', N'-79.01007695487921', 2, 2);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (6, N'activity', N'Caballitos de Totora en Huanchaco', N'Paseo en las milenarias embarcaciones artesanales usadas por los moches.', N'-8.118555046731096', N'-79.04134011910271', 2, 21);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (7, N'location', N'Museo Tumbas Reales de Sipán', N'Uno de los museos arqueológicos más importantes del continente, albergando el ajuar del Señor de Sipán.', N'-6.759150726871941', N'-79.83888802933677', 3, 23);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (8, N'food', N'Arroz con Pato a la Chiclayana', N'Plato bandera de Lambayeque preparado con culantro, cerveza negra y pato tierno.', N'-6.771403366188165', N'-79.8526596635363', 3, 8);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (9, N'activity', N'Visita al Mercado de Brujos', N'Recorrido para conocer las plantas medicinales y rituales místicos tradicionales.', N'-6.775439985518598', N'-79.83304597218462', 3, 7);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (10, N'location', N'Baños del Inca', N'Pozas de aguas termales medicinales con propiedades curativas de origen volcánico.', N'-7.164587016096087', N'-78.52013998185981', 4, 22);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (11, N'food', N'Caldo Verde y Humitas', N'Sopa tradicional con hierbas andinas, acompañada de humitas de choclo fresco.', N'-7.1816833490913305', N'-78.50074375990515', 4, 17);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (12, N'activity', N'Las Ventanillas de Otuzco', N'Exploración de la necrópolis pre-inca tallada en farallones de roca volcánica.', N'-7.1478533670674675', N'-78.50220524682489', 4, 4);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (13, N'location', N'Playa Máncora', N'Principal destino de surf, relax y avistamiento de ballenas jorobadas.', N'-5.185588025961221', N'-80.61877375935869', 5, 23);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (14, N'food', N'Seco de Chabelo', N'Plato piurano a base de plátano verde machacado, cecina y chicha de jora.', N'-5.180096655593016', N'-80.63303755283314', 5, 22);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (15, N'activity', N'Taller de Cerámica en Chulucanas', N'Aprende las técnicas ancestrales de decoración y quemado de vasijas de arcilla.', N'-5.2103617381410485', N'-80.63277449241771', 5, 2);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (16, N'activity', N'Windsurf en El Faro', N'Navega en uno de los puntos con viento constante más valorados del continente.', N'-7.405320617671651', N'-79.58317981831757', 6, 1);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (17, N'food', N'Ceviche de Calamar y Conchas Negras', N'Disfruta de mariscos frescos extraídos directamente del litoral pacasmayino.', N'-7.410785676479403', N'-79.58148037548104', 6, 21);
INSERT INTO [experience] ([experienceId], [type], [name], [description], [lat], [lng], [destinationDestinationId], [galeryImageId]) VALUES (18, N'location', N'Isla Blanca', N'Paseo costero en lancha a la hermosa reserva natural habitada por lobos marinos y aves guaneras.', N'-9.072225151918405', N'-78.57398550570669', 7, 4);
